module up_counter_16_en
(
  input rst,
  input clk,
  input en,

  output reg [15:0] count
);

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst) 
	begin
      count <= 16'b0000000000000000;
    end 
	else if (en)
	begin
      count <= count + 1;
    end
  end

endmodule
